mapper.select:
SELECT DISTINCT spp.id, sph.`id` AS dispatchId, sph.dispatchSeq, ROUND( spps.`approveAmount` / REPLACE(sph.`dispatchAmount`, ",", "") * 100, 2 ) AS ratio, spps.approveAmount AS amount, spps.`confirmTime`, spps.`paymentTime`, spps.`remark`, spps.`id` AS sseId, spps.`confirmTime` AS createTime, IFNULL(spp.`createBy`, u.`user_name`) AS createBy, JSON_merge_patch(IFNULL(spp.customInfo, "{}"), CONCAT( '{', CONCAT('"createName":"', IFNULL(spp.customInfo ->> "$.createName", ui.realName), '"'), CONCAT(',"useage":"', IFNULL(spps.useage,""), '"'), CONCAT(',"paystate":"', IFNULL(spps.paystate,""), '"'), CONCAT(',"approveState":"', IFNULL(spps.approveState,""), '"'), CONCAT(',"approveAmount":"', IFNULL(spps.approveAmount, ""), '"'), CONCAT(',"offerNum":"', IFNULL(spps.offerNum, ""), '"'), '}')) AS customInfo FROM `pm_subcontract_project_payment_sse` spps LEFT JOIN `pm_dispatch_project_header` sph ON sph.`dispatchNo` = REPLACE(spps.`subcontractNo`, " ", "") LEFT JOIN `pm_dispatch_project_settlement` spp ON sph.`id` = spp.`dispatchId` AND spp.`disabled` = FALSE LEFT JOIN t_user u ON spps.`workNo` = SUBSTR(u.`user_name`, 2) LEFT JOIN t_user_info ui ON u.`user_id` = ui.`user_id`
and ui.compID = #{orgId, jdbcType=INTEGER}
WHERE sph.id IS NOT NULL AND 0 = IFNULL(spp.`sseId`, 0) ORDER BY spps.`confirmTime`, sph.id
